    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Couch Potato Recovery - 2w 3x/wk',
    'sedentary',
    3,
    60,
    ARRAY['Promote active recovery', 'Reduce injury risk']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Couch Potato Recovery'
ON CONFLICT DO NOTHING;

